/**
 * Self-contained reducer test for deterministic juggling-orbit formalization.
 *
 * Run:
 *   pnpm run gnode -- run open-source/gnosis/src/__tests__/juggling-orbit-formalization.test.ts
 */

import assert from 'node:assert';
import {
  JUGGLING_ORBIT_THEOREM_IDS,
  deriveJugglingOrbitFormalization,
  type JugglingOrbitFormalizationInput,
} from '../juggling-orbit-formalization';

const BASE_PATTERN: JugglingOrbitFormalizationInput = {
  period: 2,
  generatedAt: '2026-04-10T00:00:00.000Z',
  source: 'test-suite',
  machineOnlyMultiplexThreshold: 2,
  machineOnlyAngleThresholdDeg: 12,
  machineOnlySpeedRatioThreshold: 1.3,
  throws: [
    {
      beat: 1,
      fromHand: 'right',
      flightBeats: 3,
      lane: 1,
      angleDeg: 8,
      speed: 7.1,
      label: 'h',
    },
    {
      beat: 0,
      fromHand: 'left',
      flightBeats: 3,
      lane: 1,
      angleDeg: 34,
      speed: 11,
      label: 'b',
    },
    {
      beat: 1,
      fromHand: 'left',
      flightBeats: 2,
      lane: 0,
      angleDeg: 7,
      speed: 7.1,
      label: 'e',
    },
    {
      beat: 0,
      fromHand: 'right',
      flightBeats: 3,
      lane: 1,
      angleDeg: 9,
      speed: 7.2,
      label: 'd',
    },
    {
      beat: 1,
      fromHand: 'left',
      flightBeats: 3,
      lane: 1,
      angleDeg: 31,
      speed: 10.6,
      label: 'f',
    },
    {
      beat: 0,
      fromHand: 'left',
      flightBeats: 2,
      lane: 0,
      angleDeg: 6,
      speed: 7,
      label: 'a',
    },
    {
      beat: 0,
      fromHand: 'right',
      flightBeats: 2,
      lane: 0,
      angleDeg: 8,
      speed: 7,
      label: 'c',
    },
    {
      beat: 1,
      fromHand: 'right',
      flightBeats: 2,
      lane: 0,
      angleDeg: 7,
      speed: 7,
      label: 'g',
    },
  ],
};

const deterministicA = deriveJugglingOrbitFormalization(BASE_PATTERN);
const deterministicB = deriveJugglingOrbitFormalization({
  ...BASE_PATTERN,
  throws: [...BASE_PATTERN.throws].reverse(),
});

assert.deepStrictEqual(deterministicA, deterministicB);
assert.strictEqual(deterministicA.generatedAt, '2026-04-10T00:00:00.000Z');
assert.strictEqual(deterministicA.source, 'test-suite');
assert.strictEqual(deterministicA.period, 2);
assert.strictEqual(deterministicA.normalizedThrows.length, 8);
assert.strictEqual(deterministicA.transitions.length, 8);
assert.strictEqual(deterministicA.aggregate.throwCount, 8);
assert.strictEqual(deterministicA.aggregate.transitionCount, 8);
assert.strictEqual(deterministicA.aggregate.maxMultiplexPerBeatHand, 2);
assert.strictEqual(deterministicA.aggregate.conservationMismatchCount, 0);
assert.strictEqual(deterministicA.aggregate.openTransitionCount, 0);
assert.ok(deterministicA.aggregate.orbitCount >= 1);
assert.ok(deterministicA.aggregate.closedOrbitCount >= 1);
assert.ok(
  deterministicA.asymmetricMultiplexWitnesses.some((witness) => witness.asymmetric)
);
assert.ok(
  deterministicA.asymmetricMultiplexWitnesses.some(
    (witness) => witness.machineOnlyCandidate
  )
);

for (const theoremId of JUGGLING_ORBIT_THEOREM_IDS) {
  assert.ok(deterministicA.theoremIds.includes(theoremId));
}

const mismatchBundle = deriveJugglingOrbitFormalization({
  period: 2,
  generatedAt: '2026-04-10T00:00:01.000Z',
  source: 'test-suite',
  throws: [
    {
      beat: 0,
      fromHand: 'left',
      flightBeats: 3,
      lane: 0,
      angleDeg: 18,
      speed: 9,
      label: 'solo-cross',
    },
  ],
});

assert.strictEqual(mismatchBundle.normalizedThrows.length, 1);
assert.strictEqual(mismatchBundle.transitions.length, 1);
assert.strictEqual(mismatchBundle.aggregate.throwCount, 1);
assert.strictEqual(mismatchBundle.aggregate.openTransitionCount, 1);
assert.strictEqual(mismatchBundle.aggregate.conservationMismatchCount, 2);
assert.strictEqual(mismatchBundle.asymmetricMultiplexWitnesses.length, 0);
assert.ok(mismatchBundle.beatHandBalances.some((entry) => !entry.balanced));

console.log('juggling-orbit-formalization: all tests passed');
